// Backup service worker. The real SW is generated by vite-plugin-pwa /
// Workbox during `npm run build`. This file is only used if you prefer to
// drop the plugin and ship a hand-written SW; it is NOT registered by
// default - main.ts relies on vite-plugin-pwa's auto-registration.

const CACHE = 'moonlight-shell-v1';
const SHELL = ['/', '/index.html', '/manifest.webmanifest', '/icons/icon.svg'];

self.addEventListener('install', (event) => {
  event.waitUntil(caches.open(CACHE).then((c) => c.addAll(SHELL)));
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(keys.filter((k) => k !== CACHE).map((k) => caches.delete(k))),
    ),
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);
  // Never cache the proxy/API traffic.
  if (url.pathname.startsWith('/api/') || url.pathname.startsWith('/proxy/')) return;
  // Never cache the wasm binary - we want fresh on every page load.
  if (url.pathname.endsWith('.wasm')) return;
  event.respondWith(
    caches.match(event.request).then((cached) => cached || fetch(event.request)),
  );
});
